def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    n = len(bins)
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.25
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-(15 * ratio)) + 0.12
        elif 0.4 < ratio <= 0.7:
            score = np.log1p((1 - ratio) * 10) * 0.3 + 0.08
        else:
            power_sum = 0.0
            sign = 1
            for k in range(1, 8):
                term = sign * (ratio ** (k + 1)) / (k * 2.0)
                power_sum += term
                sign = -sign
            score = abs(power_sum) + 0.03
        neighbors_influence = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    neighbors_influence += diff_ratio * weight * 0.05
        inv_capacity = 1.0 / (capacity + 1e-5)
        capacity_factor = np.cbrt(capacity)
        combined_factor = (neighbors_influence * 2 + score) / (capacity_factor + inv_capacity * 10)
        if combined_factor < 0:
            combined_factor = 0
        priorities[i] = combined_factor
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 10
    return priorities
